/**
 * API Client
 * 
 * Centralized HTTP client for all API requests.
 * Provides consistent error handling, headers, and base URL configuration.
 */

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------

import { config } from '../lib/config';

const API_BASE_URL = config.api.baseUrl;

const DEFAULT_HEADERS = {
    'Content-Type': 'application/json',
    'Accept': 'application/json',
};

const DEFAULT_TIMEOUT = config.api.timeout;

// ---------------------------------------------------------------------------
// Error Handling
// ---------------------------------------------------------------------------

import { ApiError, normalizeError } from './errors';

// ---------------------------------------------------------------------------
// Request Builder
// ---------------------------------------------------------------------------

/**
 * Build the full URL for an API request.
 */
function buildUrl(endpoint, params = null) {
    // Remove leading slash if present to avoid double slashes
    const path = endpoint.startsWith('/') ? endpoint.slice(1) : endpoint;
    const url = new URL(path, API_BASE_URL || window.location.origin);

    if (params) {
        Object.entries(params).forEach(([key, value]) => {
            if (value !== undefined && value !== null) {
                url.searchParams.append(key, String(value));
            }
        });
    }

    return url.toString();
}

/**
 * Build headers for a request.
 * Merges default headers with custom headers.
 */
function buildHeaders(customHeaders = {}) {
    return {
        ...DEFAULT_HEADERS,
        ...customHeaders,
    };
}

// ---------------------------------------------------------------------------
// Core Request Function
// ---------------------------------------------------------------------------

/**
 * Execute an API request.
 * 
 * @param {string} endpoint - API endpoint (e.g., '/users/123')
 * @param {Object} options - Request options
 * @param {string} options.method - HTTP method (GET, POST, PUT, DELETE, PATCH)
 * @param {Object} options.body - Request body (will be JSON stringified)
 * @param {Object} options.headers - Custom headers
 * @param {Object} options.params - URL query parameters
 * @param {number} options.timeout - Request timeout in milliseconds
 * @param {AbortSignal} options.signal - AbortController signal for cancellation
 * @returns {Promise<any>} - Parsed response data
 * @throws {ApiError} - Normalized error
 */
async function request(endpoint, options = {}) {
    const {
        method = 'GET',
        body = null,
        headers = {},
        params = null,
        timeout = DEFAULT_TIMEOUT,
        signal = null,
    } = options;

    const url = buildUrl(endpoint, params);
    const requestHeaders = buildHeaders(headers);

    // Setup timeout via AbortController
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), timeout);

    // Merge external signal with timeout signal
    const combinedSignal = signal
        ? AbortSignal.any([signal, controller.signal])
        : controller.signal;

    const fetchOptions = {
        method,
        headers: requestHeaders,
        signal: combinedSignal,
        credentials: 'same-origin', // Include cookies for same-origin requests
    };

    // Add body for non-GET requests
    if (body && method !== 'GET') {
        fetchOptions.body = JSON.stringify(body);
    }

    let response;

    try {
        response = await fetch(url, fetchOptions);
    } catch (error) {
        clearTimeout(timeoutId);
        throw await normalizeError(error);
    }

    clearTimeout(timeoutId);

    // Handle error responses
    if (!response.ok) {
        throw await normalizeError(null, response);
    }

    // Handle empty responses (204 No Content)
    if (response.status === 204) {
        return null;
    }

    // Parse JSON response
    try {
        const contentType = response.headers.get('content-type') || '';
        if (contentType.includes('application/json')) {
            return await response.json();
        }
        return await response.text();
    } catch (error) {
        throw new ApiError(
            'Failed to parse server response',
            response.status,
            'PARSE_ERROR'
        );
    }
}

// ---------------------------------------------------------------------------
// HTTP Method Shortcuts
// ---------------------------------------------------------------------------

/**
 * API Client instance with convenient HTTP method shortcuts.
 */
export const apiClient = {
    /**
     * GET request
     * @param {string} endpoint
     * @param {Object} options - { params, headers, timeout, signal }
     */
    get: (endpoint, options = {}) =>
        request(endpoint, { ...options, method: 'GET' }),

    /**
     * POST request
     * @param {string} endpoint
     * @param {Object} body - Request body
     * @param {Object} options - { headers, timeout, signal }
     */
    post: (endpoint, body = null, options = {}) =>
        request(endpoint, { ...options, method: 'POST', body }),

    /**
     * PUT request
     * @param {string} endpoint
     * @param {Object} body - Request body
     * @param {Object} options - { headers, timeout, signal }
     */
    put: (endpoint, body = null, options = {}) =>
        request(endpoint, { ...options, method: 'PUT', body }),

    /**
     * PATCH request
     * @param {string} endpoint
     * @param {Object} body - Request body
     * @param {Object} options - { headers, timeout, signal }
     */
    patch: (endpoint, body = null, options = {}) =>
        request(endpoint, { ...options, method: 'PATCH', body }),

    /**
     * DELETE request
     * @param {string} endpoint
     * @param {Object} options - { params, headers, timeout, signal }
     */
    delete: (endpoint, options = {}) =>
        request(endpoint, { ...options, method: 'DELETE' }),
};

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

export default apiClient;

import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { ChevronDown } from "lucide-react";

export function ProfileDropdown({
    onAccount,
    onSettings,
    onFAQ,
    onLogout,
}) {
    const [open, setOpen] = useState(false);

    // Inline styles to replicate the visual design without relying on Tailwind
    const styles = {
        container: {
            position: 'relative',
            display: 'inline-block',
            textAlign: 'left',
        },
        triggerButton: {
            display: 'flex',
            alignItems: 'center',
            gap: '8px',
            borderRadius: '6px',
            backgroundColor: '#ffffff',
            border: '1px solid #d1d5db',
            padding: '8px 16px',
            fontSize: '14px',
            fontWeight: 500,
            color: '#374151',
            cursor: 'pointer',
            boxShadow: '0 1px 2px 0 rgba(0, 0, 0, 0.05)',
            outline: 'none',
        },
        dropdownMenu: {
            position: 'absolute',
            right: 0,
            zIndex: 50,
            marginTop: '8px',
            width: '240px',
            transformOrigin: 'top right',
            borderRadius: '8px',
            backgroundColor: '#ffffff', // The "Tile" background
            boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1), 0 2px 4px -1px rgba(0, 0, 0, 0.06)',
            border: '1px solid #e5e7eb',
            overflow: 'hidden',
        },
        header: {
            padding: '12px 16px',
            borderBottom: '1px solid #f3f4f6',
        },
        signedInText: {
            fontSize: '12px',
            color: '#6b7280',
            marginBottom: '4px',
        },
        emailText: {
            fontSize: '14px',
            fontWeight: 500,
            color: '#111827',
            whiteSpace: 'nowrap',
            overflow: 'hidden',
            textOverflow: 'ellipsis',
        },
        menuGroup: {
            padding: '4px 0',
        },
        menuItem: {
            display: 'block',
            width: '100%',
            textAlign: 'left',
            padding: '8px 16px',
            fontSize: '14px',
            color: '#374151',
            backgroundColor: 'transparent',
            border: 'none',
            cursor: 'pointer',
            transition: 'background-color 0.15s ease, color 0.15s ease',
        },
        divider: {
            borderTop: '1px solid #f3f4f6',
            margin: '0',
        }
    };

    return (
        <div style={styles.container}>
            {/* Trigger Button */}
            <button
                type="button"
                onClick={() => setOpen((v) => !v)}
                style={styles.triggerButton}
                onMouseEnter={(e) => e.currentTarget.style.backgroundColor = '#f9fafb'}
                onMouseLeave={(e) => e.currentTarget.style.backgroundColor = '#ffffff'}
            >
                BTC007
                <ChevronDown
                    size={16}
                    style={{
                        transform: open ? 'rotate(180deg)' : 'rotate(0deg)',
                        transition: 'transform 0.2s',
                        color: '#6b7280'
                    }}
                />
            </button>

            {/* Dropdown Menu */}
            <AnimatePresence>
                {open && (
                    <motion.div
                        initial={{ opacity: 0, scale: 0.95, y: -5 }}
                        animate={{ opacity: 1, scale: 1, y: 0 }}
                        exit={{ opacity: 0, scale: 0.95, y: -5 }}
                        transition={{ duration: 0.1, ease: "easeOut" }}
                        style={styles.dropdownMenu}
                        onMouseLeave={() => setOpen(false)}
                    >
                        <div style={styles.header}>
                            <p style={styles.signedInText}>Signed in as</p>
                            <p style={styles.emailText} title="btc007@gmail.com">btc007@gmail.com</p>
                        </div>

                        <div style={styles.menuGroup}>
                            <button
                                onClick={() => {
                                    onAccount?.();
                                    setOpen(false);
                                }}
                                style={styles.menuItem}
                                onMouseEnter={(e) => e.currentTarget.style.backgroundColor = '#f3f4f6'}
                                onMouseLeave={(e) => e.currentTarget.style.backgroundColor = 'transparent'}
                            >
                                Account
                            </button>
                            <button
                                onClick={() => {
                                    onSettings?.();
                                    setOpen(false);
                                }}
                                style={styles.menuItem}
                                onMouseEnter={(e) => e.currentTarget.style.backgroundColor = '#f3f4f6'}
                                onMouseLeave={(e) => e.currentTarget.style.backgroundColor = 'transparent'}
                            >
                                Settings
                            </button>
                            <button
                                onClick={() => {
                                    onFAQ?.();
                                    setOpen(false);
                                }}
                                style={styles.menuItem}
                                onMouseEnter={(e) => e.currentTarget.style.backgroundColor = '#f3f4f6'}
                                onMouseLeave={(e) => e.currentTarget.style.backgroundColor = 'transparent'}
                            >
                                FAQ
                            </button>
                        </div>

                        <div style={styles.divider}></div>

                        <div style={styles.menuGroup}>
                            <button
                                onClick={() => {
                                    onLogout?.();
                                    setOpen(false);
                                }}
                                style={styles.menuItem}
                                onMouseEnter={(e) => e.currentTarget.style.backgroundColor = '#f3f4f6'}
                                onMouseLeave={(e) => e.currentTarget.style.backgroundColor = 'transparent'}
                            >
                                Sign out
                            </button>
                        </div>
                    </motion.div>
                )}
            </AnimatePresence>
        </div>
    );
}

