import React, { useState } from 'react';
import { ChevronDown } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

const AccordionRoot = ({ children, className = '' }) => {
    return (
        <div className={`accordion-root ${className}`} style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
            {children}
        </div>
    );
};

const AccordionItem = ({ children, className = '' }) => {
    const [isOpen, setIsOpen] = useState(false);

    return (
        <div
            className={`accordion-item ${className}`}
            data-state={isOpen ? 'open' : 'closed'}
            style={{
                borderBottom: '1px solid #E2E8F0',
                paddingBottom: isOpen ? '1rem' : '0'
            }}
        >
            {React.Children.map(children, child => {
                if (React.isValidElement(child)) {
                    return React.cloneElement(child, { isOpen, setIsOpen });
                }
                return child;
            })}
        </div>
    );
};

const AccordionTrigger = ({ children, isOpen, setIsOpen, className = '' }) => {
    return (
        <button
            onClick={() => setIsOpen(!isOpen)}
            className={`accordion-trigger ${className}`}
            style={{
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'space-between',
                width: '100%',
                padding: '1rem 0',
                background: 'transparent',
                border: 'none',
                cursor: 'pointer',
                textAlign: 'left',
                fontSize: '1rem',
                fontWeight: 600,
                color: '#1E293B'
            }}
        >
            {children}
            <ChevronDown
                size={18}
                className="accordion-chevron"
                style={{
                    transform: isOpen ? 'rotate(180deg)' : 'rotate(0deg)',
                    transition: 'transform 0.2s ease',
                    color: '#64748B'
                }}
            />
        </button>
    );
};

const AccordionContent = ({ children, isOpen, className = '' }) => {
    return (
        <AnimatePresence>
            {isOpen && (
                <motion.div
                    initial={{ height: 0, opacity: 0 }}
                    animate={{ height: 'auto', opacity: 1 }}
                    exit={{ height: 0, opacity: 0 }}
                    transition={{ duration: 0.2, ease: 'easeInOut' }}
                    style={{ overflow: 'hidden' }}
                >
                    <div className={`accordion-content ${className}`} style={{ paddingBottom: '0.5rem', paddingTop: '0', color: '#64748B', fontSize: '0.95rem', lineHeight: 1.6 }}>
                        {children}
                    </div>
                </motion.div>
            )}
        </AnimatePresence>
    );
};

export { AccordionRoot, AccordionItem, AccordionTrigger, AccordionContent };

import React from 'react';
import { motion } from 'framer-motion';

export const Toggle = ({ checked, onChange, size = 'md', label, disabled = false }) => {
    // Dimensions based on size prop (currently just 'md' supported as standard)
    const dimensions = {
        md: { width: 44, height: 24, handle: 20, padding: 2 },
        sm: { width: 36, height: 20, handle: 16, padding: 2 },
        lg: { width: 52, height: 28, handle: 24, padding: 2 },
    };

    const { width, height, handle, padding } = dimensions[size] || dimensions.md;

    return (
        <label
            style={{
                display: 'inline-flex',
                alignItems: 'center',
                gap: '0.75rem',
                cursor: disabled ? 'not-allowed' : 'pointer',
                opacity: disabled ? 0.6 : 1
            }}
        >
            <div
                style={{
                    width: `${width}px`,
                    height: `${height}px`,
                    backgroundColor: checked ? '#195BAC' : '#CBD5E1',
                    borderRadius: '999px',
                    position: 'relative',
                    transition: 'background-color 0.2s ease',
                    flexShrink: 0
                }}
            >
                <input
                    type="checkbox"
                    checked={checked}
                    onChange={onChange}
                    disabled={disabled}
                    style={{ position: 'absolute', opacity: 0, cursor: 'inherit', height: '100%', width: '100%', margin: 0 }}
                    aria-label={label}
                />
                <motion.div
                    initial={false}
                    animate={{ x: checked ? width - handle - padding : padding }}
                    transition={{ type: "spring", stiffness: 500, damping: 30 }}
                    style={{
                        width: `${handle}px`,
                        height: `${handle}px`,
                        backgroundColor: 'white',
                        borderRadius: '50%',
                        position: 'absolute',
                        top: `${padding}px`,
                        boxShadow: '0 1px 2px rgba(0,0,0,0.2)'
                    }}
                />
            </div>
            {label && (
                <span style={{ fontSize: '0.9rem', color: '#1E293B', fontWeight: 500 }}>
                    {label}
                </span>
            )}
        </label>
    );
};

