                        colorClass="icon-red"
                    />
                    <ExpenseStat
                        label="Daily Average"
                        value={formatCurrency(avgDaily)}
                        subtext="Per day analysis"
                        icon={Calendar}
                        colorClass="icon-orange"
                    />
                    <ExpenseStat
                        label="Total Transactions"
                        value={expenseData.length}
                        subtext=" across 5 categories"
                        icon={Receipt}
