                                                {item.icon ? <item.icon size={18} /> : <Receipt size={18} />}
                                            </div>
                                            <div className="font-medium text-main">{item.name}</div>
                                        </div>
                                    </td>
                                    <td>
                                        <span className="category-pill">
                                            {item.category}
                                        </span>
