                                        <div className="flex items-center gap-2 text-sm text-muted">
                                            <CreditCard size={14} />
                                            {item.paymentMethod}
                                        </div>
                                    </td>
                                    <td className="font-bold text-danger">-{formatCurrency(item.amount)}</td>
