                    color: var(--text-muted);
                    font-size: 0.875rem;
                    font-weight: 500;
                    margin-bottom: 0.5rem;
                }

                .stat-value {
                    font-size: 1.75rem;
                    font-weight: 700;
                    color: var(--text-main);
                    margin-bottom: 0.25rem;
                }

                .stat-subtext {
                    font-size: 0.8rem;
                    color: #10B981; /* Green for positive growth hints */
                    font-weight: 500;
                }

                .stat-icon-wrapper {
                    width: 48px;
                    height: 48px;
                    border-radius: 12px;
                    display: flex;
                    align-items: center;
                    justify-content: center;
                }

                .icon-green { background: #DCFCE7; color: #16A34A; }
                .icon-blue { background: #DBEAFE; color: #2563EB; }
                .icon-purple { background: #F3E8FF; color: #9333EA; }

                /* Search & Filters */
                .search-wrapper {
                    position: relative;
                    flex: 1;
                    max-width: 400px;
                }
                .search-icon {
                    position: absolute;
                    left: 12px;
                    top: 50%;
                    transform: translateY(-50%);
                    color: var(--text-muted);
                }
                .search-input {
                    width: 100%;
                    padding: 0.75rem 1rem 0.75rem 2.5rem;
                    border: 1px solid var(--border-color);
                    border-radius: 10px;
                    outline: none;
                    font-size: 0.9rem;
                    background: white;
                    transition: border-color 0.2s;
