                .search-input:focus {
                    border-color: var(--primary);
                    box-shadow: 0 0 0 3px rgba(25, 91, 172, 0.1);
                }

                .filter-btn {
                    display: flex;
                    align-items: center;
                    gap: 0.5rem;
                    padding: 0.75rem 1rem;
                    background: white;
                    border: 1px solid var(--border-color);
                    border-radius: 10px;
                    font-size: 0.9rem;
                    font-weight: 500;
                    color: var(--text-main);
                    transition: all 0.2s;
                }
                .filter-btn:hover {
                    background: #F8FAFC;
                    border-color: #CBD5E1;
                }

                /* Table Styling */
                .income-list-container {
                    background: white;
                    border-radius: 16px;
                    border: 1px solid var(--border-color);
                    overflow: hidden;
                    box-shadow: 0 4px 6px -1px rgba(0,0,0,0.02);
