                .income-table th {
                    text-align: left;
                    padding: 1rem 1.5rem;
                    background: #F8FAFC;
                    border-bottom: 1px solid var(--border-color);
                    color: var(--text-muted);
                    font-weight: 600;
                    font-size: 0.8rem;
                    text-transform: uppercase;
                    letter-spacing: 0.05em;
                }

                .income-table td {
                    padding: 1rem 1.5rem;
                    border-bottom: 1px solid var(--border-color);
                    vertical-align: middle;
                    color: var(--text-main);
                }

                .income-table tr:last-child td {
                    border-bottom: none;
                }

                .income-table tr:hover td {
                    background: #F8FAFC;
                }

                .table-icon-bg {
                    width: 36px;
                    height: 36px;
                    background: #F1F5F9;
                    border-radius: 8px;
                    display: flex;
                    align-items: center;
                    justify-content: center;
                    color: var(--text-muted);
                }

                .recurring-badge {
                    display: inline-block;
                    font-size: 0.65rem;
                    padding: 0.1rem 0.5rem;
                    background: #EFF6FF;
                    color: #2563EB;
                    border-radius: 999px;
                    margin-top: 2px;
                    font-weight: 600;
                    letter-spacing: 0.02em;
                }

                .category-pill {
                    padding: 0.25rem 0.75rem;
                    background: #F1F5F9;
                    border-radius: 6px;
                    font-size: 0.85rem;
                    color: var(--text-muted);
                }

                .text-success { color: #16A34A; }
                .text-main { color: var(--text-main); }
                
                .action-btn {
                    width: 32px;
                    height: 32px;
                    border-radius: 6px;
                    display: flex;
                    align-items: center;
                    justify-content: center;
                    color: var(--text-muted);
                    transition: all 0.2s;
                }
                
                .hover-blue:hover { background: #EFF6FF; color: #2563EB; }
                .hover-red:hover { background: #FEF2F2; color: #DC2626; }

                @media (max-width: 768px) {
                    .income-table thead { display: none; }
                    .income-table tr { display: block; border-bottom: 1px solid var(--border-color); padding: 1rem; }
                    .income-table td { display: flex; justify-content: space-between; padding: 0.5rem 0; border: none; }
                    .income-table td::before { content: attr(date-label); font-weight: 600; color: var(--text-muted); display: block; }
                }
            `}</style>
        </div>
    );
};

